queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?feevalue WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFees ?child ; p:hasDebit_Cards ?parent . } GROUP BY ?child }
  ?child p:FeeValue ?feevalue .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Debit_Cards } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?feevalue WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFees ?child ; p:hasDebit_Cards ?parent . } GROUP BY ?child }
  ?child p:FeeValue ?feevalue .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Debit_Cards } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?customername ?feevalue WHERE {
  ?debit_card_fees a :Debit_Card_Fees .
  ?fees a :Fees .
  ?debit_card_fees p:hasFees ?fees .
  ?debit_cards a :Debit_Cards .
  ?debit_card_fees p:hasDebit_Cards ?debit_cards .
  ?debit_cards p:CustomerName ?customername .
  ?fees p:FeeValue ?feevalue .
} }
}
